using namespace std;

class Solution {
public:
    int maxStability(int n, vector<vector<int>>& edges, int k) {
        int low = 1;
        int high = 2 * 100000; // Maximum possible strength after upgrade
        int answer = -1;

        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (check(mid, n, edges, k)) {
                answer = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        return answer;
    }

private:
    bool check(int S, int n, vector<vector<int>>& edges, int k) {
        DSU dsu(n);
        int must_count = 0;

        for (auto& edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int s = edge[2];
            int must = edge[3];

            if (must == 1) {
                if (s < S) {
                    return false;
                }
                if (dsu.find(u) == dsu.find(v)) {
                    return false; // Cycle detected
                }
                dsu.union_nodes(u, v);
                must_count++;
            }
        }

        if (must_count > n - 1) {
            return false;
        }

        int c = dsu.count_components();
        if (c == 1) {
            return true;
        }

        vector<tuple<int, int, int>> optional;
        for (auto& edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int s = edge[2];
            int must = edge[3];

            if (must == 0) {
                if (s >= S) {
                    optional.emplace_back(u, v, 0);
                } else if (2 * s >= S) {
                    optional.emplace_back(u, v, 1);
                }
            }
        }

        sort(optional.begin(), optional.end(), [](const tuple<int, int, int>& a, const tuple<int, int, int>& b) {
            return get<2>(a) < get<2>(b);
        });

        int upgrades_used = 0;
        int edges_added = 0;

        for (auto& e : optional) {
            int u = get<0>(e);
            int v = get<1>(e);
            int cost = get<2>(e);

            if (dsu.find(u) != dsu.find(v)) {
                dsu.union_nodes(u, v);
                upgrades_used += cost;
                edges_added++;

                if (edges_added == c - 1) {
                    break;
                }
            }
        }

        return edges_added == c - 1 && upgrades_used <= k;
    }

    class DSU {
    private:
        vector<int> parent;
        vector<int> rank;
        int components;

    public:
        DSU(int n) {
            parent.resize(n);
            rank.resize(n, 0);
            components = n;
            for (int i = 0; i < n; ++i) {
                parent[i] = i;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        void union_nodes(int x, int y) {
            int x_root = find(x);
            int y_root = find(y);
            if (x_root == y_root) {
                return;
            }
            if (rank[x_root] < rank[y_root]) {
                parent[x_root] = y_root;
            } else {
                parent[y_root] = x_root;
                if (rank[x_root] == rank[y_root]) {
                    rank[x_root]++;
                }
            }
            components--;
        }

        int count_components() {
            return components;
        }
    };
};

